// Wklej to jako komponent (AccordionItem.tsx lub bezpośrednio na stronie)

'use client';

import React, { useState, useRef } from 'react';
import { ChevronDown } from 'lucide-react';

interface AccordionItemProps {
  title: string;
  paragraphs: string[];
}

export default function AccordionItem({ title, paragraphs }: AccordionItemProps) {
  const [isOpen, setIsOpen] = useState(false);
  const contentRef = useRef<HTMLDivElement>(null);

  const toggle = () => {
    setIsOpen(prev => !prev);
  };

  return (
    <div
      style={{
        padding: '24px 28px',
        borderRadius: '22px',
        background: '#FFFFFF',
        marginBottom: '18px',
        boxShadow: '0 4px 20px rgba(0,0,0,0.04)',
        border: '1px solid rgba(0,0,0,0.06)' ,
        cursor: 'pointer'
      }}
    >
      {/* Nagłówek */}
      <div
        onClick={toggle}
        style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}
      >
        <h3 style={{ fontSize: '1.2rem', fontWeight: 600, margin: 0 }}>{title}</h3>
        <ChevronDown
          size={20}
          style={{
            transition: 'transform 0.35s',
            transform: isOpen ? 'rotate(180deg)' : 'rotate(0deg)'
          }}
        />
      </div>

      {/* TREŚĆ — zawsze renderowana, animowana tylko height */}
      <div
        ref={contentRef}
        style={{
          overflow: 'hidden',
          height: isOpen ? contentRef.current?.scrollHeight : 0,
          transition: 'height 0.35s ease'
        }}
      >
        <div
          style={{
            paddingTop: '16px',
            paddingBottom: '6px',
            display: 'flex',
            flexDirection: 'column',
            gap: '12px',
            color: '#555',
            lineHeight: 1.65
          }}
        >
          {paragraphs.map((p, i) => (
            <p key={i} style={{ margin: 0 }}>{p}</p>
          ))}
        </div>
      </div>
    </div>
  );
}
